const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

export function processScenario(scenario: { steps: { op: string; items?: { type: string }[] }[] }): { results: unknown[] } {
  const results = scenario.steps.map((step) => {
    if (step.op === "quote") {
      const item = step.items![0];
      const basePremium = BASE_PREMIUMS[item.type];
      const premium = Math.ceil(basePremium * 1.10) + 5;
      return { premium };
    }
    return {};
  });
  return { results };
}

