import { describe, it, expect } from "vitest";
import { processScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  describe("Quoting a premium", () => {
    it("should return base premium plus processing fee for a single sword", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "sword", material: "steel", enchantment: 0, cursed: false },
            ],
          },
        ],
      });
      // Base premium 100G, first-insurance surcharge 10% = 110G, + 5G fee = 115G
      expect(result.results[0]).toEqual({ premium: 115 });
    });
    it("should return correct base premium for each item type (amulet, staff, potion)", () => {
      const quote = (type: string) =>
        processScenario({
          customer: { yearsWithMHPCO: 0 },
          steps: [
            {
              op: "quote" as const,
              items: [{ type, material: "silver", enchantment: 0, cursed: false }],
            },
          ],
        }).results[0];

      // Amulet: ceil(60 * 1.10) + 5 = 71
      expect(quote("amulet")).toEqual({ premium: 71 });
      // Staff: ceil(80 * 1.10) + 5 = 93
      expect(quote("staff")).toEqual({ premium: 93 });
      // Potion: ceil(40 * 1.10) + 5 = 49
      expect(quote("potion")).toEqual({ premium: 49 });
    });
    it("should return base premium of 25G for a single component", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "component", material: "moonstone", enchantment: 0, cursed: false },
            ],
          },
        ],
      });
      // Component base premium 25G, first-insurance surcharge 10% = ceil(27.5) = 28, + 5G fee = 33G
      expect(result.results[0]).toEqual({ premium: 33 });
    });
    it.todo("should charge 60G for a building block of 3 alike components");
    it.todo("should sum premiums for multiple different items");
    it.todo("should add 50% surcharge for a cursed item");
    it.todo("should add 30% surcharge for a highly enchanted item (enchantment >= 5)");
    it.todo("should apply both cursed and enchantment surcharges when both apply");
    it.todo("should apply 20% loyalty discount for long-standing customers (>= 2 years)");
    it.todo("should apply 10% initial assessment surcharge for a first insurance");
    it.todo("should apply 15% discount on each contract after the first");
    it.todo("should round premium in MHPCO's favor (ceiling)");
  });

  describe("Processing a claim", () => {
    it.todo("should apply 100G deductible to a damage event");
    it.todo("should cap total payout at twice the insurance sum");
    it.todo("should reimburse damage to highly enchanted items (enchantment >= 8) at 50%");
    it.todo("should fully reimburse damage to dragon material items");
    it.todo("should track remaining cap across multiple claims on the same policy");
    it.todo("should round payout in MHPCO's favor (floor)");
  });
});

